"""Scientific calculator with expression parsing.

Supports: +, -, *, /, ^, parentheses, and scientific functions.
"""
import math
import re
from typing import List, Optional, Tuple, Union


class CalcError(Exception):
    """Calculator error."""
    pass


class Token:
    """A token in the expression."""
    NUMBER = 'NUMBER'
    PLUS = 'PLUS'
    MINUS = 'MINUS'
    MULTIPLY = 'MULTIPLY'
    DIVIDE = 'DIVIDE'
    POWER = 'POWER'
    LPAREN = 'LPAREN'
    RPAREN = 'RPAREN'
    FUNCTION = 'FUNCTION'
    COMMA = 'COMMA'
    EOF = 'EOF'

    def __init__(self, type_: str, value=None):
        self.type = type_
        self.value = value

    def __repr__(self):
        return f'Token({self.type}, {self.value!r})'


class Tokenizer:
    """Tokenize mathematical expressions."""
    FUNCTIONS = {'sin', 'cos', 'tan', 'sqrt', 'abs', 'log', 'log10', 'exp', 'ceil', 'floor'}

    def __init__(self, text: str):
        self.text = text.strip()
        self.pos = 0

    def tokenize(self) -> List[Token]:
        tokens = []
        while self.pos < len(self.text):
            ch = self.text[self.pos]

            if ch.isspace():
                self.pos += 1
                continue

            if ch.isdigit() or ch == '.':
                tokens.append(self._read_number())
            elif ch.isalpha():
                tokens.append(self._read_name())
            elif ch == '+':
                tokens.append(Token(Token.PLUS, '+'))
                self.pos += 1
            elif ch == '-':
                tokens.append(Token(Token.MINUS, '-'))
                self.pos += 1
            elif ch == '*':
                tokens.append(Token(Token.MULTIPLY, '*'))
                self.pos += 1
            elif ch == '/':
                tokens.append(Token(Token.DIVIDE, '/'))
                self.pos += 1
            elif ch == '^':
                tokens.append(Token(Token.POWER, '^'))
                self.pos += 1
            elif ch == '(':
                tokens.append(Token(Token.LPAREN, '('))
                self.pos += 1
            elif ch == ')':
                tokens.append(Token(Token.RPAREN, ')'))
                self.pos += 1
            elif ch == ',':
                tokens.append(Token(Token.COMMA, ','))
                self.pos += 1
            else:
                raise CalcError(f'Unexpected character: {ch!r}')

        tokens.append(Token(Token.EOF))
        return tokens

    def _read_number(self) -> Token:
        start = self.pos
        has_dot = False
        while self.pos < len(self.text):
            ch = self.text[self.pos]
            if ch.isdigit():
                self.pos += 1
            elif ch == '.' and not has_dot:
                has_dot = True
                self.pos += 1
            else:
                break
        return Token(Token.NUMBER, float(self.text[start:self.pos]))

    def _read_name(self) -> Token:
        start = self.pos
        while self.pos < len(self.text) and self.text[self.pos].isalnum():
            self.pos += 1
        name = self.text[start:self.pos]
        if name in self.FUNCTIONS:
            return Token(Token.FUNCTION, name)
        elif name == 'pi':
            return Token(Token.NUMBER, math.pi)
        elif name == 'e':
            return Token(Token.NUMBER, math.e)
        else:
            raise CalcError(f'Unknown name: {name!r}')


class Parser:
    """Recursive descent parser for mathematical expressions.

    Grammar:
        expr     -> term (('+' | '-') term)*
        term     -> power (('*' | '/') power)*
        power    -> unary ('^' unary)*
        unary    -> '-' unary | call
        call     -> FUNCTION '(' expr (',' expr)* ')' | primary
        primary  -> NUMBER | '(' expr ')'
    """

    def __init__(self, tokens: List[Token]):
        self.tokens = tokens
        self.pos = 0

    def parse(self) -> float:
        result = self._expr()
        if self.tokens[self.pos].type != Token.EOF:
            raise CalcError(f'Unexpected token: {self.tokens[self.pos]}')
        return result

    def _current(self) -> Token:
        return self.tokens[self.pos]

    def _eat(self, type_: str) -> Token:
        token = self._current()
        if token.type != type_:
            raise CalcError(f'Expected {type_}, got {token.type}')
        self.pos += 1
        return token

    def _expr(self) -> float:
        result = self._term()
        while self._current().type in (Token.PLUS, Token.MINUS):
            op = self._current()
            self.pos += 1
            right = self._term()
            if op.type == Token.PLUS:
                result += right
            else:
                result -= right
        return result

    def _term(self) -> float:
        result = self._power()
        while self._current().type in (Token.MULTIPLY, Token.DIVIDE):
            op = self._current()
            self.pos += 1
            right = self._power()
            if op.type == Token.MULTIPLY:
                result *= right
            else:
                if right == 0:
                    raise CalcError('Division by zero')
                result /= right
        return result

    def _power(self) -> float:
        base = self._unary()
        if self._current().type == Token.POWER:
            self.pos += 1
            exp = self._unary()
            return base ** exp
        return base

    def _unary(self) -> float:
        if self._current().type == Token.MINUS:
            self.pos += 1
            return -self._unary()
        if self._current().type == Token.PLUS:
            self.pos += 1
            return self._unary()
        return self._call()

    def _call(self) -> float:
        if self._current().type == Token.FUNCTION:
            name = self._current().value
            self.pos += 1
            self._eat(Token.LPAREN)
            args = [self._expr()]
            while self._current().type == Token.COMMA:
                self.pos += 1
                args.append(self._expr())
            self._eat(Token.RPAREN)
            return self._apply_function(name, args)
        return self._primary()

    def _primary(self) -> float:
        token = self._current()
        if token.type == Token.NUMBER:
            self.pos += 1
            return token.value
        if token.type == Token.LPAREN:
            self.pos += 1
            result = self._expr()
            self._eat(Token.RPAREN)
            return result
        raise CalcError(f'Unexpected token: {token}')

    def _apply_function(self, name: str, args: List[float]) -> float:
        if len(args) != 1:
            raise CalcError(f'{name} takes exactly 1 argument')
        arg = args[0]
        funcs = {
            'sin': math.sin,
            'cos': math.cos,
            'tan': math.tan,
            'sqrt': math.sqrt,
            'abs': abs,
            'log': math.log,
            'log10': math.log10,
            'exp': math.exp,
            'ceil': math.ceil,
            'floor': math.floor,
        }
        if name not in funcs:
            raise CalcError(f'Unknown function: {name}')
        try:
            return funcs[name](arg)
        except (ValueError, OverflowError) as e:
            raise CalcError(f'{name}({arg}): {e}')


def evaluate(expression: str) -> float:
    """Evaluate a mathematical expression string."""
    if not expression or not expression.strip():
        raise CalcError('Empty expression')
    tokenizer = Tokenizer(expression)
    tokens = tokenizer.tokenize()
    parser = Parser(tokens)
    return parser.parse()


def format_result(value: float) -> str:
    """Format a numeric result for display."""
    if value == int(value) and abs(value) < 1e15:
        return str(int(value))
    return f'{value:.10g}'


if __name__ == '__main__':
    import sys
    if len(sys.argv) > 1:
        expr = ' '.join(sys.argv[1:])
    else:
        expr = input('Enter expression: ')
    try:
        result = evaluate(expr)
        print(format_result(result))
    except CalcError as e:
        print(f'Error: {e}', file=sys.stderr)
        sys.exit(1)
